SELECT ROUND(100.0 * COUNT(CASE WHEN bond.bond_type = 'single' AND molecule.label LIKE '%carcinogenic%' THEN 1 END) / COUNT(*), 5) AS proportion
FROM bond
JOIN molecule ON bond.molecule_id = molecule.molecule_id;

SELECT ROUND(100.0 * SUM(CASE WHEN bond.bond_type = 'single' AND molecule.label LIKE '%carcinogen%' THEN 1 ELSE 0 END) / SUM(CASE WHEN bond.bond_type = 'single' THEN 1 ELSE 0 END), 5) AS percentage
FROM bond
JOIN molecule ON bond.molecule_id = molecule.molecule_id;
